noncompliant:
// Namespace with extern C - confusing and problematic
namespace ns1 {
  extern "C" void doSomething(); // Noncompliant: namespace ignored
}

// extern C block containing namespace
extern "C" {
  namespace ns2 { // Noncompliant: namespace has no effect
    void process();
  }
}

compliant:
// Proper use of extern C without namespace
extern "C" void doSomething();

// Or use namespace without extern C
namespace ns1 {
  void doSomething(); // Compliant: clear C++ linkage
}

// Separate extern C declarations
extern "C" {
  void process_c_function();
  void another_c_function();
}

// Separate namespace declarations
namespace ns2 {
  void cpp_function();
}
